VALUES
  ('islands-6f0ba476-moex-00014', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-d35177eb', 'sub-islands-6f0ba476-01', NULL, 'single_choice', '甲公司X5年1月初以$800,000購置生產設備，其耐用年限8年，殘值$20,000，以雙倍餘額遞減 法提列折舊費用。X7年初發生維修費用$5,000，另為提升設備生產效率花費$100,000進行改良， 同時發現此生產設備僅剩5年耐用年限，殘值不變，並改以直線法提列折舊費用。X8年6月底 將其以$395,000售出，請問處分此資產的損益金額為多少？', '["損失$2,125", "損失$5,625", "利得$4,000", "利得$5,500"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "f78fbdb14e03", "answer_pdf_sha1": "f43123b0c751", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00015', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-d35177eb', 'sub-islands-6f0ba476-01', NULL, 'single_choice', '有關資產減損的敘述，下列何者錯誤？', '["資產提列減損損失後，在有證據顯示資產以前年度認列之減損損失已不存在，已可迴轉全部已 提列之減損損失", "當資產帳面金額大於可回收金額時，需提列資產減損損失", "資產減損會計處理除適用於不動產、廠房及設備外，也適用於無形資產", "當企業淨值大於股價時，需進行資產減損測試 41620 60420"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "f78fbdb14e03", "answer_pdf_sha1": "f43123b0c751", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00016', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-d35177eb', 'sub-islands-6f0ba476-01', NULL, 'single_choice', '下列有關無形資產之敘述有幾項正確？①因推出新產品而產生開辦費，具有未來經濟效益，可以', '["非確定耐用年限之無形資產，在未有減損跡象的情境下，亦須每年進行減損 測試", "當商譽認列減損損失後，因其可回收金額增加，可迴轉部分已認列的減損損失", "企業 為維護專利權而發生之訴訟支出，在勝訴的情況下可將該支出資本化", "1項"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "f78fbdb14e03", "answer_pdf_sha1": "f43123b0c751", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00017', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-d35177eb', 'sub-islands-6f0ba476-01', NULL, 'single_choice', '乙公司出售 1 項客製化的設備，並提供 2 年內免費更換零件的售後保證服務，每個零件成本為 $80,000。估計發生更換1個零件的機率為40%，更換2個零件的機率為35%，更換3個零件的 機率為25%。請問此售後保證服務最佳估計金額為多少？', '["$80,000", "$148,000", "$160,000", "$240,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "f78fbdb14e03", "answer_pdf_sha1": "f43123b0c751", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00018', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-d35177eb', 'sub-islands-6f0ba476-01', NULL, 'single_choice', '甲公司X5年7月初購買一棟位於商業區之商辦大樓，其估計耐用年限為20年，殘值$285,000,000， 未來將出租以賺取租金收益，除支付大樓購買成本$580,000,000，另支出稅捐及交易成本 $5,000,000。被委託之乙仲介公司順利於同年9月，以每月$600,000租金將大樓出租予丙集團作 為辦公室使用，甲公司須支付乙仲介公司1個月的租金作為仲介費用。甲公司對該商辦大樓之會 計處理採公允價值模式，於X5年底，此商辦大樓之公允價值為$584,500,000。請問此商辦大樓相 關交易對甲公司X5年本期損益的影響為何？', '["增加本期損益$1,300,000", "增加本期損益$1,800,000", "減少本期損益$3,700,000", "減少本期損益$5,700,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "f78fbdb14e03", "answer_pdf_sha1": "f43123b0c751", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00019', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-d35177eb', 'sub-islands-6f0ba476-01', NULL, 'single_choice', '假設其他條件相同情況下，有幾項被賦予特殊權利之特別股，其價格發行高於無此特殊權利之特', '["累積特別股", "參加特別股", "可轉換特別股", "可贖回特別股"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "f78fbdb14e03", "answer_pdf_sha1": "f43123b0c751", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00020', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-d35177eb', 'sub-islands-6f0ba476-01', NULL, 'single_choice', '丙寵物用品店存貨係以零售價法計價，該店當年淨進貨的成本價與零售價分別為$1,200,000 與 $1,800,000，期初存貨的成本價與零售價分別為$100,000 與$180,000。當期銷貨收入淨額為 $1,450,000，期末存貨估計金額為：', '["$487,750", "$347,980", "$357,550", "$387,950"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "f78fbdb14e03", "answer_pdf_sha1": "f43123b0c751", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00021', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-d35177eb', 'sub-islands-6f0ba476-01', NULL, 'single_choice', '甲公司在X1年初購買乙公司平價發行之公司債，面額$100,000，票面利率6%，每年的1月1日 及 7 月 1 日付息。以透過其他綜合損益按公允價值衡量進行會計處理，X1 年底此公司債市價 $110,000。X2年7月1日以市價$106,000將全部乙公司公司債售出，請問對甲公司X2年的本期 損益及其他綜合損益影響的金額為多少？', '["本期損益$3,000；其他綜合損益($4,000)", "本期損益$3,000；其他綜合損益($10,000)", "本期損益$9,000；其他綜合損益($4,000)", "本期損益$9,000；其他綜合損益($10,000)"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "f78fbdb14e03", "answer_pdf_sha1": "f43123b0c751", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00022', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-d35177eb', 'sub-islands-6f0ba476-01', NULL, 'single_choice', '乙公司X1年設備增加$850,000，累計折舊增加$60,000，同年認列折舊費用$700,000，處分設備 利得$36,000。另以$1,650,000購買一台設備，請問X1年處分設備的售價為多少金額？', '["$96,000", "$150,000", "$186,000", "$196,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "f78fbdb14e03", "answer_pdf_sha1": "f43123b0c751", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00023', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-d35177eb', 'sub-islands-6f0ba476-01', NULL, 'single_choice', '假設乙公司皆以賖帳購買存貨，X1年存貨增加$30,000，應付帳款增加$20,000，支付給供應商之 現金為$590,000，請問乙公司X1年度的銷貨成本為多少金額？', '["$580,000", "$590,000", "$600,000", "$610,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "f78fbdb14e03", "answer_pdf_sha1": "f43123b0c751", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL)
